   291→func buildAddress(c *entity.Contact) string {
   292→	var parts []string
   293→	if c.Prefecture != "" {
   294→		parts = append(parts, c.Prefecture)
   295→	}
   296→	if c.City != "" {
   297→		parts = append(parts, c.City)
   298→	}
   299→	if c.Street != "" {
   300→		parts = append(parts, c.Street)
   301→	}
   302→	if c.Building != "" {
   303→		parts = append(parts, c.Building)
   304→	}
   305→	return strings.Join(parts, "")
   306→}
   307→
   308→func buildSenderAddress(s *entity.Sender) string {
   309→	var parts []string
   310→	if s.Prefecture != "" {
   311→		parts = append(parts, s.Prefecture)
   312→	}
   313→	if s.City != "" {
   314→		parts = append(parts, s.City)
   315→	}
   316→	if s.Street != "" {
   317→		parts = append(parts, s.Street)
   318→	}
   319→	if s.Building != "" {
   320→		parts = append(parts, s.Building)
   321→	}
   322→	return strings.Join(parts, "")
   323→}
   324→
   325→func imageType(path string) string {
   326→	lower := strings.ToLower(path)
   327→	switch {
   328→	case strings.HasSuffix(lower, ".png"):
   329→		return "PNG"
   330→	case strings.HasSuffix(lower, ".jpg"), strings.HasSuffix(lower, ".jpeg"):
   331→		return "JPG"
   332→	default:
   333→		return "PNG"
   334→	}
   335→}
