package pdf

import (
	"bytes"
	"fmt"
	"os"
	"runtime"
	"strings"

	"github.com/jung-kurt/gofpdf"
	qrcode "github.com/skip2/go-qrcode"

	"atena-label/internal/entity"
)

// Generator implements PDF generation using gofpdf.
type Generator struct {
	fontPath string // path to a Japanese TrueType font (.ttf/.ttc)
}

// NewGenerator creates a Generator. Pass an empty fontPath for auto-detection.
func NewGenerator(fontPath string) *Generator {
	if fontPath == "" {
		fontPath = detectJapaneseFont()
	}
	return &Generator{fontPath: fontPath}
}

// detectJapaneseFont returns the first available Japanese TTF/TTC path on the system.
func detectJapaneseFont() string {
	var candidates []string
	switch runtime.GOOS {
	case "darwin":
		candidates = []string{
			"/System/Library/Fonts/ヒラギノ明朝 ProN.ttc",
			"/Library/Fonts/Hiragino Mincho ProN W3.otf",
			"/System/Library/Fonts/Hiragino Mincho ProN.ttc",
			"/Library/Fonts/YuMincho.ttc",
		}
	case "windows":
		candidates = []string{
			`C:\Windows\Fonts\msmincho.ttc`,
			`C:\Windows\Fonts\YuMincho.ttc`,
			`C:\Windows\Fonts\mingliu.ttc`,
		}
	default:
		candidates = []string{
			"/usr/share/fonts/truetype/noto/NotoSerifCJK-Regular.ttc",
			"/usr/share/fonts/opentype/noto/NotoSerifCJK-Regular.ttc",
			"/usr/share/fonts/truetype/fonts-japanese-mincho.ttf",
		}
	}
	for _, p := range candidates {
		if _, err := os.Stat(p); err == nil {
			return p
		}
	}
	return ""
}

// GenerateLabelPDF generates an A4 label PDF and returns the raw bytes.
func (g *Generator) GenerateLabelPDF(
	job entity.PrintJob,
	contacts []entity.Contact,
	sender *entity.Sender,
) ([]byte, error) {
	pdf := gofpdf.New("P", "mm", "A4", "")
	pdf.SetMargins(0, 0, 0)
	pdf.SetAutoPageBreak(false, 0)
	pdf.SetCompression(true)

	// Register Japanese font if available.
	// Use AddUTF8FontFromBytes to avoid gofpdf's internal filepath.Join
	// mangling absolute paths when its fontpath is non-empty.
	const fontName = "jfont"
	hasJFont := false
	if g.fontPath != "" {
		if fontBytes, err := os.ReadFile(g.fontPath); err == nil {
			pdf.AddUTF8FontFromBytes(fontName, "", fontBytes)
			if pdf.Error() == nil {
				hasJFont = true
			}
		}
	}

	setFont := func(size float64) {
		if hasJFont {
			pdf.SetFont(fontName, "", size)
		} else {
			pdf.SetFont("Courier", "", size)
		}
	}

	layout := job.LabelLayout
	tmpl := job.Template

	labelsPerPage := layout.Columns * layout.Rows
	if labelsPerPage == 0 {
		return nil, fmt.Errorf("invalid label layout: columns=%d rows=%d", layout.Columns, layout.Rows)
	}

	// Pre-generate QR PNG bytes once (reused for every label).
	var qrPNG []byte
	if job.QRConfig != nil && job.QRConfig.Enabled && job.QRConfig.Content != "" {
		sizePx := job.QRConfig.Size
		if sizePx <= 0 {
			sizePx = 128
		}
		var err error
		qrPNG, err = qrcode.Encode(job.QRConfig.Content, qrcode.Medium, sizePx)
		if err != nil {
			// QR generation failure is non-fatal.
			qrPNG = nil
		}
	}

	for i, contact := range contacts {
		if i%labelsPerPage == 0 {
			pdf.AddPage()
		}

		pageIdx := i % labelsPerPage
		col := pageIdx % layout.Columns
		row := pageIdx / layout.Columns

		originX := layout.MarginLeft + float64(col)*(layout.LabelWidth+layout.GapX)
		originY := layout.MarginTop + float64(row)*(layout.LabelHeight+layout.GapY)

		// Watermark background.
		if job.Watermark != nil && job.Watermark.FilePath != "" {
			if _, err := os.Stat(job.Watermark.FilePath); err == nil {
				imgType := imageType(job.Watermark.FilePath)
				opts := gofpdf.ImageOptions{ImageType: imgType}
				pdf.ImageOptions(job.Watermark.FilePath, originX, originY, layout.LabelWidth, layout.LabelHeight, false, opts, 0, "")
			}
		}

		// Label content.
		drawLabel(pdf, setFont, &contact, sender, tmpl, originX, originY)

		// QR code.
		if qrPNG != nil {
			drawQR(pdf, job.QRConfig, qrPNG, originX, originY, layout.LabelWidth, layout.LabelHeight, i)
		}
	}

	var buf bytes.Buffer
	if err := pdf.Output(&buf); err != nil {
		return nil, fmt.Errorf("pdf output: %w", err)
	}
	return buf.Bytes(), nil
}

// drawQR places a pre-generated QR PNG at the configured position within the label.
func drawQR(pdf *gofpdf.Fpdf, qr *entity.QRConfig, pngBytes []byte, originX, originY, labelW, labelH float64, idx int) {
	// size in mm: qr.Size pixels * 0.264583 mm/px (96 dpi)
	sizeMM := float64(qr.Size) * 0.264583
	if sizeMM < 15 {
		sizeMM = 15 // minimum readable QR size
	}

	var qrX, qrY float64
	switch qr.Position {
	case "top-left":
		qrX = originX + 1
		qrY = originY + 1
	case "top-right":
		qrX = originX + labelW - sizeMM - 1
		qrY = originY + 1
	case "bottom-left":
		qrX = originX + 1
		qrY = originY + labelH - sizeMM - 1
	default: // "bottom-right"
		qrX = originX + labelW - sizeMM - 1
		qrY = originY + labelH - sizeMM - 1
	}

	// Register once with a fixed key; gofpdf caches it after first registration.
	const imgKey = "qr_code"
	if idx == 0 {
		reader := bytes.NewReader(pngBytes)
		pdf.RegisterImageOptionsReader(imgKey, gofpdf.ImageOptions{ImageType: "PNG"}, reader)
	}
	pdf.ImageOptions(imgKey, qrX, qrY, sizeMM, sizeMM, false, gofpdf.ImageOptions{ImageType: "PNG"}, 0, "")
}

// drawLabel renders postal code, recipient and sender onto a single label cell.
func drawLabel(
	pdf *gofpdf.Fpdf,
	setFont func(float64),
	contact *entity.Contact,
	sender *entity.Sender,
	tmpl entity.Template,
	ox, oy float64,
) {
	pdf.SetTextColor(0, 0, 0)

	// Postal code digits.
	if tmpl.PostalCode != nil && contact.PostalCode != "" {
		setFont(tmpl.PostalCode.FontSize)
		digits := strings.ReplaceAll(contact.PostalCode, "-", "")
		spacing := tmpl.PostalCode.DigitSpacing
		if spacing <= 0 {
			spacing = 4
		}
		cellH := tmpl.PostalCode.FontSize * 0.4
		for i, ch := range digits {
			xPos := ox + tmpl.PostalCode.X + float64(i)*spacing
			pdf.SetXY(xPos, oy+tmpl.PostalCode.Y)
			pdf.CellFormat(spacing, cellH, string(ch), "", 0, "C", false, 0, "")
		}
	}

	// Recipient name.
	rec := tmpl.Recipient
	honorific := contact.Honorific
	if honorific == "" {
		honorific = "様"
	}

	var nameLines []string
	if contact.Company != "" {
		nameLines = append(nameLines, contact.Company)
		if contact.Department != "" {
			nameLines = append(nameLines, contact.Department)
		}
	}
	fullName := contact.FamilyName + contact.GivenName + " " + honorific
	nameLines = append(nameLines, fullName)

	addr := buildAddress(contact)

	if tmpl.Orientation == "vertical" {
		setFont(rec.NameFont)
		xOff := ox + rec.NameX
		for _, line := range nameLines {
			drawVerticalText(pdf, line, xOff, oy+rec.NameY, rec.NameFont)
			xOff -= rec.NameFont * 0.5 // next column to the left
		}

		setFont(rec.AddressFont)
		drawVerticalText(pdf, addr, ox+rec.AddressX, oy+rec.AddressY, rec.AddressFont)
	} else {
		setFont(rec.NameFont)
		lineH := rec.NameFont * 0.5
		for i, line := range nameLines {
			pdf.SetXY(ox+rec.NameX, oy+rec.NameY+float64(i)*lineH)
			pdf.CellFormat(0, lineH, line, "", 0, "L", false, 0, "")
		}

		setFont(rec.AddressFont)
		pdf.SetXY(ox+rec.AddressX, oy+rec.AddressY)
		pdf.CellFormat(0, rec.AddressFont*0.5, addr, "", 0, "L", false, 0, "")
	}

	// Sender.
	if sender != nil {
		snd := tmpl.Sender
		senderName := sender.FamilyName + sender.GivenName
		if sender.Company != "" {
			senderName = sender.Company + " " + senderName
		}
		senderAddr := buildSenderAddress(sender)

		if tmpl.Orientation == "vertical" {
			setFont(snd.NameFont)
			drawVerticalText(pdf, senderName, ox+snd.NameX, oy+snd.NameY, snd.NameFont)
			setFont(snd.AddressFont)
			drawVerticalText(pdf, senderAddr, ox+snd.AddressX, oy+snd.AddressY, snd.AddressFont)
		} else {
			setFont(snd.NameFont)
			pdf.SetXY(ox+snd.NameX, oy+snd.NameY)
			pdf.CellFormat(0, snd.NameFont*0.5, senderName, "", 0, "L", false, 0, "")
			setFont(snd.AddressFont)
			pdf.SetXY(ox+snd.AddressX, oy+snd.AddressY)
			pdf.CellFormat(0, snd.AddressFont*0.5, senderAddr, "", 0, "L", false, 0, "")
		}
	}
}

// drawVerticalText places each rune top-to-bottom in a single column.
func drawVerticalText(pdf *gofpdf.Fpdf, text string, x, y, fontSize float64) {
	charW := fontSize * 0.45
	lineH := fontSize * 0.48
	for i, ch := range text {
		pdf.SetXY(x, y+float64(i)*lineH)
		pdf.CellFormat(charW, lineH, string(ch), "", 0, "C", false, 0, "")
	}
}

func buildAddress(c *entity.Contact) string {
	var parts []string
	if c.Prefecture != "" {
		parts = append(parts, c.Prefecture)
	}
	if c.City != "" {
		parts = append(parts, c.City)
	}
	if c.Street != "" {
		parts = append(parts, c.Street)
	}
	if c.Building != "" {
		parts = append(parts, c.Building)
	}
	return strings.Join(parts, "")
}

func buildSenderAddress(s *entity.Sender) string {
	var parts []string
	if s.Prefecture != "" {
		parts = append(parts, s.Prefecture)
	}
	if s.City != "" {
		parts = append(parts, s.City)
	}
	if s.Street != "" {
		parts = append(parts, s.Street)
	}
	if s.Building != "" {
		parts = append(parts, s.Building)
	}
	return strings.Join(parts, "")
}

func imageType(path string) string {
	lower := strings.ToLower(path)
	switch {
	case strings.HasSuffix(lower, ".png"):
		return "PNG"
	case strings.HasSuffix(lower, ".jpg"), strings.HasSuffix(lower, ".jpeg"):
		return "JPG"
	default:
		return "PNG"
	}
}

import { useEffect, useRef } from 'react'
import type { Contact, Template } from '../../types'
import { drawVerticalBlock } from '../../lib/verticalText'

/** 1mm あたりのピクセル数 (96 dpi 基準) */
const MM_TO_PX = 96 / 25.4 // ≈ 3.78

/**
 * デフォルトテンプレート: A4 12面ラベル (86.4×42.3mm)
 * テンプレート選択 UI が実装されるまでのフォールバック用。
 */
export const DEFAULT_TEMPLATE: Template = {
  id: 'default-a4-12',
  name: '標準 (A4 12面)',
  orientation: 'vertical',
  labelWidth: 86.4,
  labelHeight: 42.3,
  postalCode: {
    x: 36,        // 〒マーク左端 (mm)
    y: 4.5,       // 上端からの距離 (mm)
    digitSpacing: 5.5,
    fontSize: 10,
  },
  recipient: {
    nameX: 79,    // 氏名カラム右端 (mm)
    nameY: 8,     // 上端からの距離 (mm)
    nameFont: 13,
    addressX: 69, // 住所ブロック右端 (mm)
    addressY: 8,  // 上端からの距離 (mm)
    addressFont: 8.5,
  },
  sender: {
    nameX: 16,    // 差出人氏名カラム右端 (mm)
    nameY: 24,
    nameFont: 6.5,
    addressX: 8,  // 差出人住所ブロック右端 (mm)
    addressY: 24,
    addressFont: 5.5,
  },
}

/** 郵便番号を "NNN-NNNN" 形式に整形する */
function formatPostalCode(raw: string): string {
  const digits = raw.replace(/\D/g, '')
  if (digits.length === 7) return `${digits.slice(0, 3)}-${digits.slice(3)}`
  return raw
}

/** px 変換ヘルパー */
function mm(value: number, scale: number): number {
  return value * MM_TO_PX * scale
}

interface LabelCanvasProps {
  contact: Contact
  template?: Template
  /** 表示倍率 (デフォルト 1.0) */
  zoom?: number
}

export default function LabelCanvas({
  contact,
  template = DEFAULT_TEMPLATE,
  zoom = 1,
}: LabelCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const canvasW = Math.round(mm(template.labelWidth, zoom))
  const canvasH = Math.round(mm(template.labelHeight, zoom))

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    // デバイスピクセル比を考慮した高解像度レンダリング
    const dpr = window.devicePixelRatio || 1
    canvas.width = canvasW * dpr
    canvas.height = canvasH * dpr
    canvas.style.width = `${canvasW}px`
    canvas.style.height = `${canvasH}px`
    ctx.scale(dpr, dpr)

    renderLabel(ctx, contact, template, zoom)
  }, [contact, template, zoom, canvasW, canvasH])

  return (
    <canvas
      ref={canvasRef}
      style={{ width: canvasW, height: canvasH }}
      className="shadow-sm"
    />
  )
}

function renderLabel(
  ctx: CanvasRenderingContext2D,
  contact: Contact,
  tpl: Template,
  zoom: number,
): void {
  const s = zoom // スケール係数 (zoom のみ。MM_TO_PX は mm() 内で適用済み)
  const W = mm(tpl.labelWidth, s)
  const H = mm(tpl.labelHeight, s)

  // ─── 背景 ───────────────────────────────────────────────
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, W, H)

  // ─── 外枠 ───────────────────────────────────────────────
  ctx.strokeStyle = '#d1d5db'
  ctx.lineWidth = 0.5
  ctx.strokeRect(0.5, 0.5, W - 1, H - 1)

  // ─── 郵便番号 ────────────────────────────────────────────
  if (tpl.postalCode && contact.postalCode) {
    const pc = tpl.postalCode
    const fontSize = mm(pc.fontSize / 2.835, s) // pt → mm → px (1pt≈0.353mm)
    const spacing = mm(pc.digitSpacing, s)
    const startX = mm(pc.x, s)
    const baseY = mm(pc.y, s)

    ctx.fillStyle = '#111827'
    ctx.font = `${fontSize}px "Hiragino Kaku Gothic ProN", "Meiryo", sans-serif`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'

    // 〒マーク
    ctx.fillText('〒', startX - spacing * 0.3, baseY)

    const digits = contact.postalCode.replace(/\D/g, '')
    const formatted = formatPostalCode(digits)
    // ハイフン込みで1文字ずつ等間隔に描画
    let ox = startX + spacing * 0.5
    for (const ch of formatted) {
      ctx.fillText(ch, ox, baseY)
      ox += ch === '-' ? spacing * 0.5 : spacing
    }
  }

  // ─── 宛先 氏名 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const nameFontPx = mm(rc.nameFont / 2.835, s)
    const name = `${contact.familyName}${contact.givenName}`
    const honorific = contact.honorific || '様'

    ctx.fillStyle = '#111827'
    ctx.font = `${nameFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    // 氏名: 右端カラム、敬称は独立した右隣カラム
    drawVerticalBlock({
      ctx,
      lines: [honorific, name],
      rightX: mm(rc.nameX, s),
      topY: mm(rc.nameY, s),
      fontSize: nameFontPx,
      convertNumbers: false,
    })
  }

  // ─── 宛先 住所 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const addrFontPx = mm(rc.addressFont / 2.835, s)

    // 住所を2列に分割: 都道府県+市区町村 / 番地+建物名
    const addrLine1 = `${contact.prefecture}${contact.city}`
    const addrLine2 = `${contact.street}${contact.building ? `　${contact.building}` : ''}`

    ctx.fillStyle = '#111827'
    ctx.font = `${addrFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    drawVerticalBlock({
      ctx,
      lines: [addrLine1, addrLine2].filter(Boolean),
      rightX: mm(rc.addressX, s),
      topY: mm(rc.addressY, s),
      fontSize: addrFontPx,
      convertNumbers: true,
    })
  }

  // ─── 差出人（会社名があれば部署・会社を優先） ──────────────
  const senderName = contact.company
    ? `${contact.company}${contact.department ? `　${contact.department}` : ''}`
    : null

  // 差出人エリアは将来 Sender エンティティで置き換える
  // (Phase 6: 差出人管理) — 現状は連絡先の会社情報をダミーで表示しない
  // 仕様: 差出人は別エンティティなので、ここでは表示領域の余白のみ確保
  void senderName // 未使用警告抑制
}

import { useEffect, useState } from 'react'
import { GenerateLabelPDF, GetTempPDFPath, PrintPDF, SavePDFFileDialog, GetSenders } from '../../wailsjs/go/main/App'
import { entity } from '../../wailsjs/go/models'
import { useContactStore } from '../stores/contactStore'
import { useDecorationStore } from '../stores/decorationStore'
import { useLabelStore } from '../stores/labelStore'
import { useSenderStore } from '../stores/senderStore'
import { useShallow } from 'zustand/shallow'

interface Props {
  onClose: () => void
}

export default function PrintConfirmDialog({ onClose }: Props) {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [selectedSenderId, setSelectedSenderId] = useState('')

  const { contacts, selectedIds } = useContactStore(
    useShallow((s) => ({ contacts: s.contacts, selectedIds: s.selectedIds })),
  )
  const { watermark, qrConfig } = useDecorationStore(
    useShallow((s) => ({ watermark: s.watermark, qrConfig: s.qrConfig })),
  )
  const layout = useLabelStore((s) => s.layout)
  const { senders, setSenders } = useSenderStore(
    useShallow((s) => ({ senders: s.senders, setSenders: s.setSenders })),
  )

  useEffect(() => {
    GetSenders()
      .then((list) => {
        const loaded = list ?? []
        setSenders(loaded)
        const def = loaded.find((s) => s.isDefault)
        if (def) setSelectedSenderId(def.id)
      })
      .catch(() => {})
  }, [])

  const selectedContacts = contacts.filter((c) => selectedIds.has(c.id))
  const count = selectedContacts.length

  const paperLabel = `${layout.paperWidth}×${layout.paperHeight}mm (${layout.columns}列×${layout.rows}行)`

  function buildJob(): entity.PrintJob {
    return entity.PrintJob.createFrom({
      contactIds: selectedContacts.map((c) => c.id),
      template: {
        id: '',
        name: 'default',
        orientation: 'vertical',
        labelWidth: layout.labelWidth,
        labelHeight: layout.labelHeight,
        recipient: { nameX: 0, nameY: 0, nameFont: 0, addressX: 0, addressY: 0, addressFont: 0 },
        sender: { nameX: 0, nameY: 0, nameFont: 0, addressX: 0, addressY: 0, addressFont: 0 },
      },
      senderId: selectedSenderId,
      labelLayout: layout,
      watermark: watermark ?? undefined,
      qrConfig: qrConfig.enabled ? qrConfig : undefined,
    })
  }

  async function run(action: () => Promise<void>) {
    setError(null)
    setLoading(true)
    try {
      await action()
      onClose()
    } catch (e) {
      setError(String(e))
    } finally {
      setLoading(false)
    }
  }

  function handleSavePDF() {
    return run(async () => {
      const savePath = await SavePDFFileDialog('ラベル.pdf')
      if (!savePath) return
      await GenerateLabelPDF(buildJob(), savePath)
    })
  }

  function handlePrint() {
    return run(async () => {
      const tmpPath = await GetTempPDFPath()
      const outPath = await GenerateLabelPDF(buildJob(), tmpPath)
      await PrintPDF(outPath)
    })
  }

  const selectedSender = senders.find((s) => s.id === selectedSenderId)

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl w-80 p-6 space-y-4">
        <h2 className="text-base font-semibold text-gray-800">印刷確認</h2>

        <div className="space-y-2 text-sm text-gray-700">
          <div className="flex justify-between">
            <span className="text-gray-500">印刷枚数</span>
            <span className="font-medium">{count} 件</span>
          </div>
          <div className="flex justify-between">
            <span className="text-gray-500">用紙</span>
            <span className="font-medium text-right">{paperLabel}</span>
          </div>
        </div>

        {/* 差出人選択 */}
        <div>
          <label className="block text-xs text-gray-500 mb-1">差出人</label>
          <select
            value={selectedSenderId}
            onChange={(e) => setSelectedSenderId(e.target.value)}
            className="w-full text-sm border border-gray-300 rounded px-2 py-1.5 focus:outline-none focus:ring-1 focus:ring-blue-400"
          >
            <option value="">なし</option>
            {senders.map((s) => (
              <option key={s.id} value={s.id}>
                {s.familyName} {s.givenName}
                {s.company ? ` (${s.company})` : ''}
                {s.isDefault ? ' ★' : ''}
              </option>
            ))}
          </select>
          {selectedSender && (
            <p className="text-xs text-gray-400 mt-1 truncate">
              〒{selectedSender.postalCode} {selectedSender.prefecture}{selectedSender.city}{selectedSender.street}
            </p>
          )}
        </div>

        {error && (
          <p className="text-xs text-red-600 bg-red-50 rounded px-2 py-1">{error}</p>
        )}

        <div className="flex flex-col gap-2 pt-1">
          <button
            onClick={handlePrint}
            disabled={loading || count === 0}
            className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm font-medium hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? '処理中...' : '印刷'}
          </button>
          <button
            onClick={handleSavePDF}
            disabled={loading || count === 0}
            className="w-full px-4 py-2 border border-gray-300 text-gray-700 rounded text-sm hover:bg-gray-50 disabled:opacity-50"
          >
            PDF保存
          </button>
          <button
            onClick={onClose}
            disabled={loading}
            className="w-full px-4 py-2 text-gray-500 text-sm hover:text-gray-700"
          >
            キャンセル
          </button>
        </div>
      </div>
    </div>
  )
}

/**
 * 縦書きテキスト描画エンジン (Canvas API)
 * Canvas (プレビュー) と gofpdf (印刷) で同じ見た目になるよう
 * テンプレートJSONを共通のソースとして使用する。
 */

/** 拗音・促音（小さいかな）—右寄り・上寄りにオフセット */
const SMALL_KANA = new Set(
  'ぁぃぅぇぉゃゅょゎゕゖっァィゥェォャュョヮヵヶッ',
)

/** 長音符・波ダッシュ—90度回転して縦に表示 */
const ROTATE_90 = new Set('ーｰ〜～―─━')

/** 句読点・括弧の位置調整 (dx, dy は fontSize の倍率) */
const PUNCT_OFFSET: Record<string, [number, number]> = {
  '。': [0.35, -0.35],
  '、': [0.35, -0.35],
  '．': [0.35, -0.35],
  '，': [0.35, -0.35],
  '・': [0.0, 0.0],
  '「': [-0.15, 0.25],
  '」': [-0.15, -0.25],
  '『': [-0.15, 0.25],
  '』': [-0.15, -0.25],
  '（': [-0.1, 0.3],
  '）': [-0.1, -0.3],
  '【': [-0.1, 0.3],
  '】': [-0.1, -0.3],
  '〔': [-0.1, 0.3],
  '〕': [-0.1, -0.3],
}

/** アラビア数字→漢数字 */
const ARABIC_TO_KANJI: Record<string, string> = {
  '0': '〇',
  '1': '一',
  '2': '二',
  '3': '三',
  '4': '四',
  '5': '五',
  '6': '六',
  '7': '七',
  '8': '八',
  '9': '九',
}

/** アラビア数字を漢数字に変換する */
export function toKanjiNumerals(text: string): string {
  return text.replace(/[0-9]/g, (d) => ARABIC_TO_KANJI[d] ?? d)
}

export interface DrawVerticalColumnOptions {
  /** Canvas 2D コンテキスト */
  ctx: CanvasRenderingContext2D
  /** 描画するテキスト */
  text: string
  /** カラム中心の x 座標（ピクセル） */
  x: number
  /** 開始 y 座標（ピクセル）—最初の文字の上端 */
  y: number
  /** フォントサイズ（ピクセル） */
  fontSize: number
  /** 文字間の余白（fontSize に対する倍率, デフォルト 0.05） */
  charGap?: number
  /** アラビア数字を漢数字に変換するか */
  convertNumbers?: boolean
}

/**
 * 1列の縦書きテキストを描画し、消費した高さ（ピクセル）を返す。
 * ctx の fillStyle / font は呼び出し側で設定すること。
 */
export function drawVerticalColumn(opts: DrawVerticalColumnOptions): number {
  const { ctx, x, y, fontSize, charGap = 0.05, convertNumbers = false } = opts
  const text = convertNumbers ? toKanjiNumerals(opts.text) : opts.text
  const chars = [...text] // サロゲートペア対応
  const cellHeight = fontSize * (1 + charGap)

  ctx.save()
  ctx.textAlign = 'center'
  ctx.textBaseline = 'middle'

  let currentY = y + fontSize / 2

  for (const char of chars) {
    const cx = x
    const cy = currentY

    if (ROTATE_90.has(char)) {
      ctx.save()
      ctx.translate(cx, cy)
      ctx.rotate(Math.PI / 2)
      ctx.fillText(char, 0, 0)
      ctx.restore()
    } else if (SMALL_KANA.has(char)) {
      // 小さいかなは右上方向にずらす
      ctx.fillText(char, cx + fontSize * 0.12, cy - fontSize * 0.1)
    } else if (char in PUNCT_OFFSET) {
      const [dx, dy] = PUNCT_OFFSET[char]
      ctx.fillText(char, cx + fontSize * dx, cy + fontSize * dy)
    } else {
      ctx.fillText(char, cx, cy)
    }

    currentY += cellHeight
  }

  ctx.restore()
  return chars.length * cellHeight
}

export interface DrawVerticalBlockOptions {
  ctx: CanvasRenderingContext2D
  /** 各要素が1列になる文字列の配列（右から左へ並ぶ） */
  lines: string[]
  /** 右端の x 座標（ピクセル） */
  rightX: number
  /** 上端の y 座標（ピクセル） */
  topY: number
  /** フォントサイズ（ピクセル） */
  fontSize: number
  /** 列間の水平余白（ピクセル, デフォルト fontSize * 0.2） */
  columnGap?: number
  /** 文字間の余白（fontSize に対する倍率, デフォルト 0.05） */
  charGap?: number
  /** アラビア数字を漢数字に変換するか */
  convertNumbers?: boolean
}

/**
 * 複数列の縦書きテキストブロックを描画する。
 * lines[0] が最右列、lines[1] が左隣、... となる。
 */
export function drawVerticalBlock(opts: DrawVerticalBlockOptions): void {
  const { ctx, lines, rightX, topY, fontSize, columnGap, charGap, convertNumbers } = opts
  const colGap = columnGap ?? fontSize * 0.2
  const colWidth = fontSize + colGap

  lines.forEach((line, i) => {
    if (!line) return
    const colCenterX = rightX - fontSize / 2 - colWidth * i
    drawVerticalColumn({
      ctx,
      text: line,
      x: colCenterX,
      y: topY,
      fontSize,
      charGap,
      convertNumbers,
    })
  })
}

import { useShallow } from 'zustand/shallow'
import { useLabelStore } from '../../stores/labelStore'
